when (state) {
    is NotCompleted -> error("Not completed")
    is CompletedExceptionally -> return // already completed exception or cancelled, nothing to do
    is CompletedContinuation<*> -> {
        check(!state.cancelled) { "Must be called at most once" }
        val update = state.copy(cancelCause = cause)
        if (_state.compareAndSet(state, update)) {
            state.invokeHandlers(this, cause)
            return // done
        }
    }
    else -> {
        // completed normally without marker class, promote to CompletedContinuation in case
        // if invokeOnCancellation if called later
        if (_state.compareAndSet(state, CompletedContinuation(state, cancelCause = cause))) {
            return // done
        }
    }
}

when (state) {
    is NotCompleted -> {
        val update = resumedState(state, proposedUpdate, resumeMode, onCancellation, idempotent)
        if (!_state.compareAndSet(state, update)) return@loop // retry on cas failure
        detachChildIfNonReusable()
        return RESUME_TOKEN
    }
    is CompletedContinuation<*> -> {
        return if (idempotent != null && state.idempotentResume === idempotent) {
            assert { state.result == proposedUpdate } // "Non-idempotent resume"
            RESUME_TOKEN // resumed with the same token -- ok
        } else {
            null // resumed with a different token or non-idempotent -- too late
        }
    }
    else -> return null // cannot resume -- not active anymore
}

when (updateCellSend(segment, index, element, s, waiter, false)) {
    RESULT_RENDEZVOUS -> {
        segment.cleanPrev()
        onRendezvousOrBuffered()
    }
    RESULT_BUFFERED -> {
        onRendezvousOrBuffered()
    }
    RESULT_SUSPEND -> {
        waiter.prepareSenderForSuspension(segment, index)
    }
    RESULT_CLOSED -> {
        if (s < receiversCounter) segment.cleanPrev()
        onClosed()
    }
    RESULT_FAILED -> {
        segment.cleanPrev()
        sendImpl(
            element = element,
            waiter = waiter,
            onRendezvousOrBuffered = onRendezvousOrBuffered,
            onSuspend = { _, _ -> },
            onClosed = onClosed,
        )
    }
    else -> error("unexpected")
}

while (true) {
    sb.append("${segment.hexAddress}=[${if (segment.isRemoved) "*" else ""}${segment.id},prev=${segment.prev?.hexAddress},")
    repeat(SEGMENT_SIZE) { i ->
        val cellState = segment.getState(i)
        val element = segment.getElement(i)
        val cellStateString = when (cellState) {
            is CancellableContinuation<*> -> "cont"
            is SelectInstance<*> -> "select"
            is ReceiveCatching<*> -> "receiveCatching"
            is SendBroadcast -> "send(broadcast)"
            is WaiterEB -> "EB($cellState)"
            else -> cellState.toString()
        }
        sb.append("[$i]=($cellStateString,$element),")
    }
    sb.append("next=${segment.next?.hexAddress}]  ")
    // Process the next segment if exists.
    segment = segment.next ?: break
}

when (queue) {
    null -> if (_queue.compareAndSet(null, task)) return true
    is Queue<*> -> {
        when ((queue as Queue<Runnable>).addLast(task)) {
            Queue.ADD_SUCCESS -> return true
            Queue.ADD_CLOSED -> return false
            Queue.ADD_FROZEN -> _queue.compareAndSet(queue, queue.next())
        }
    }
    else -> when {
        queue === CLOSED_EMPTY -> return false
        else -> {
            // update to full-blown queue to add one more
            val newQueue = Queue<Runnable>(Queue.INITIAL_CAPACITY, singleConsumer = true)
            newQueue.addLast(queue as Runnable)
            newQueue.addLast(task)
            if (_queue.compareAndSet(queue, newQueue)) return true
        }
    }
}

if (onBufferOverflow != BufferOverflow.SUSPEND) {
    // this additional buffer never suspends => overwrite preceding buffering configuration
    newCapacity = capacity
    newOverflow = onBufferOverflow
} else {
    // combine capacities, keep previous overflow strategy
    newCapacity = when {
        this.capacity == Channel.OPTIONAL_CHANNEL -> capacity
        capacity == Channel.OPTIONAL_CHANNEL -> this.capacity
        this.capacity == Channel.BUFFERED -> capacity
        capacity == Channel.BUFFERED -> this.capacity
        else -> {
            // sanity checks
            assert { this.capacity >= 0 }
            assert { capacity >= 0 }
            // combine capacities clamping to UNLIMITED on overflow
            val sum = this.capacity + capacity
            if (sum >= 0) sum else Channel.UNLIMITED // unlimited on int overflow
        }
    }
    newOverflow = this.onBufferOverflow
}

if (maxResumeCount > 0) { // collect emitters to resume if we have them
            resumes = arrayOfNulls(maxResumeCount)
            var resumeCount = 0
            val buffer = buffer!!
            for (curEmitterIndex in newBufferEndIndex until newQueueEndIndex) {
                val emitter = buffer.getBufferAt(curEmitterIndex)
                if (emitter !== NO_VALUE) {
                    emitter as Emitter // must have Emitter class
                    resumes[resumeCount++] = emitter.cont
                    buffer.setBufferAt(curEmitterIndex, NO_VALUE) // make as canceled if we moved ahead
                    buffer.setBufferAt(newBufferEndIndex, emitter.value)
                    newBufferEndIndex++
                    if (resumeCount >= maxResumeCount) break // enough resumed, done
                }
            }
        }

try {
    var fairnessCounter = 0
    while (true) {
        try {
            currentTask.run()
        } catch (e: Throwable) {
            handleCoroutineException(EmptyCoroutineContext, e)
        }
        currentTask = obtainTaskOrDeallocateWorker() ?: return
        // 16 is our out-of-thin-air constant to emulate fairness. Used in JS dispatchers as well
        if (++fairnessCounter >= 16 && dispatcher.safeIsDispatchNeeded(this@LimitedDispatcher)) {
            // Do "yield" to let other views execute their runnable as well
            // Note that we do not decrement 'runningWorkers' as we are still committed to our part of work
            dispatcher.safeDispatch(this@LimitedDispatcher, this)
            return
        }
    }
} catch (e: Throwable) {
    // If the worker failed, we should deallocate its slot
    synchronized(workerAllocationLock) {
        runningWorkers.decrementAndGet()
    }
    throw e
}

while (true) {
    val newCapacity = size.coerceAtLeast(MIN_CAPACITY / 4).takeHighestOneBit() * 4
    val newCore = Core(newCapacity)
    for (index in 0 until allocated) {
        // load the key
        val w = keys[index].value
        val k = w?.get()
        if (w != null && k == null) removeCleanedAt(index) // weak ref was here, but collected
        // mark value so that it cannot be changed while we rehash to new core
        var value: Any?
        while (true) {
            value = values[index].value
            if (value is Marked) { // already marked -- good
                value = value.ref
                break
            }
            // try mark
            if (values[index].compareAndSet(value, value.mark())) break
        }
        if (k != null && value != null) {
            val oldValue = newCore.putImpl(k, value as V, w)
            if (oldValue === REHASH) continue@retry // retry if we underestimated capacity
            assert(oldValue == null)
        }
    }
    return newCore // rehashed everything successfully
}

