while (true) {
    when (val index = decodeElementIndex(descriptor)) {
        CompositeDecoder.DECODE_DONE -> {
            break@mainLoop
        }
        0 -> {
            klassName = decodeStringElement(descriptor, index)
        }
        1 -> {
            klassName = requireNotNull(klassName) { "Cannot read polymorphic value before its type token" }
            val serializer = findPolymorphicSerializer(this, klassName)
            value = decodeSerializableElement(descriptor, index, serializer)
        }
        else -> throw SerializationException(
            "Invalid index in polymorphic deserialization of " +
                (klassName ?: "unknown class") +
                "\n Expected 0, 1 or DECODE_DONE(-1), but found $index"
        )
    }
}

when (this) {
    Collection::class, List::class, MutableList::class, ArrayList::class -> ArrayListSerializer(serializers[0])
    HashSet::class -> HashSetSerializer(serializers[0])
    Set::class, MutableSet::class, LinkedHashSet::class -> LinkedHashSetSerializer(serializers[0])
    HashMap::class -> HashMapSerializer(serializers[0], serializers[1])
    Map::class, MutableMap::class, LinkedHashMap::class -> LinkedHashMapSerializer(
        serializers[0],
        serializers[1]
    )

    Map.Entry::class -> MapEntrySerializer(serializers[0], serializers[1])
    Pair::class -> PairSerializer(serializers[0], serializers[1])
    Triple::class -> TripleSerializer(serializers[0], serializers[1], serializers[2])
    else -> {
        if (isReferenceArray(this)) {
            ArraySerializer(elementClassifierIfArray() as KClass<Any>, serializers[0])
        } else {
            null
        }
    }
}

if (cbor.configuration.ignoreUnknownKeys) {
    val knownIndex: Int
    while (true) {
        if (isDone()) return CompositeDecoder.DECODE_DONE
        val (elemName, tags) = decodeElementNameWithTagsLenient(descriptor)
        readProperties++

        val index = elemName?.let { descriptor.getElementIndex(it) } ?: CompositeDecoder.UNKNOWN_NAME
        if (index == CompositeDecoder.UNKNOWN_NAME) {
            parser.skipElement(tags)
        } else {
            verifyKeyTags(descriptor, index, tags)
            knownIndex = index
            break
        }
    }
    knownIndex
} else {
    if (isDone()) return CompositeDecoder.DECODE_DONE
    val (elemName, tags) = decodeElementNameWithTags(descriptor)
    readProperties++
    descriptor.getElementIndexOrThrow(elemName).also { index ->
        verifyKeyTags(descriptor, index, tags)
    }
}

do {
            if (isIndefinite()) {
                lengthStack.add(LENGTH_STACK_INDEFINITE)
            } else if (isEnd()) {
                if (lengthStack.removeLastOrNull() != LENGTH_STACK_INDEFINITE)
                    throw CborDecodingException("next data item", peekCurByteOrFail())
                prune(lengthStack)
            } else {
                val header = peekCurByteOrFail() and MAJOR_TYPE_MASK
                val length = elementLength()
                if (header == HEADER_TAG) {
                    val _ = readUnsignedIntegerIgnoringMajorType { "tag" }
                } else if (header == HEADER_ARRAY || header == HEADER_MAP) {
                    if (length > 0) lengthStack.add(length)
                    else prune(lengthStack) // empty map or array automatically completes
                } else {
                    input.skip(length)
                    prune(lengthStack)
                }
            }

            readByte()
        } while (lengthStack.isNotEmpty())

do {
            val header = peekCurByteOrFail()
            if (header and MAJOR_TYPE_MASK != majorType) {
                throw CborDecodingException(
                    "a header of a chunk with a major type bits matching $majorType",
                    header
                )
            }
            if (header and ADDITIONAL_INFO_MASK == ADDITIONAL_INFORMATION_INDEFINITE_LENGTH) {
                throw CborDecodingException("a fixed-length chunk", header)
            }
            val length = readUnsignedIntegerIgnoringMajorType { "length of a fixed-length chunk" }
                .asSizedElementLength(majorType)
            byteStrings.add(input.readExactNBytes(length))
            readByte()
        } while (!isEnd())

when (halfExp) {
    HALF_PRECISION_MAX_EXPONENT -> {
        // if exponent maximal - value is NaN or Infinity
        exp = SINGLE_PRECISION_MAX_EXPONENT
        mant = halfMant
    }

    0 -> {
        if (halfMant == 0) {
            // if exponent and mantissa are zero - value is zero
            mant = 0
            exp = 0
        } else {
            // if exponent is zero and mantissa non-zero - value denormalized. normalize it
            var res = Float.fromBits(normalizeBaseBits + halfMant)
            res -= SINGLE_PRECISION_NORMALIZE_BASE
            return if (negative) -res else res
        }
    }

    else -> {
        // normalized value
        exp = (halfExp + (SINGLE_PRECISION_EXPONENT_BIAS - HALF_PRECISION_EXPONENT_BIAS))
        mant = halfMant
    }
}

if (encoder is HoconEncoder) {
    // We determine that it is divisible by 1024 (2^10).
    // And if it is divisible, then the number itself is shifted to the right by 10.
    // And so on until we find one that is no longer divisible by 1024.
    // ((n & ((1 << m) - 1)) == 0)
    val andVal = BigInteger.valueOf(1023) // ((2^10) - 1) = 0x3ff = 1023
    var bytes = value.toBytesBigInteger()
    var unitIndex = 0
    while (bytes.and(andVal) == BigInteger.ZERO) { // n & 0x3ff == 0
        if (unitIndex < memoryUnitFormats.lastIndex) {
            bytes = bytes.shiftRight(10)
            unitIndex++
        } else break
    }
    encoder.encodeString("$bytes ${memoryUnitFormats[unitIndex]}")
} else {
    throwUnsupportedFormatException("ConfigMemorySizeSerializer")
}

if (element is SerialDescriptor) {
    if (element.kind == StructureKind.LIST) {
        if (indicies[it] != -1) {
            append("[")
            append(indicies[it])
            append("]")
        }
    } else {
        val idx = indicies[it]
        // If an actual element is being decoded
        if (idx >= 0) {
            append(".")
            append(element.getElementName(idx))
        }
    }
} else if (element === RedactedKey) {
    // Technically, this is out of spec of JsonPath. But parsing such a query would result in an error, which is reasonable.
    append("[<debug info disabled>]")
} else if (element !== Tombstone) {
    append("[")
    // All non-indicies should be properly quoted by JsonPath convention
    append("'")
    // Else -- map key
    append(element)
    append("'")
    append("]")
}
